from PIL import Image
import numpy as np

img = Image.open('/Users/mugen/Codebase/chart_derendering/data/chartmuseum/images/NBAmissPlayOffs.png')
arr = np.array(img)

# Let's do a complete scan at y=210 to identify all column boundaries
print('Full scan at y=210 (Atlanta Hawks):')
prev_type = None
start = None
segments = []
for x in range(180, 580):
    pixel = arr[210, x]
    r, g, b = int(pixel[0]), int(pixel[1]), int(pixel[2])
    if r > 240 and g > 240 and b > 240:
        t = 'W'
    elif abs(r-g) < 20 and abs(g-b) < 20 and r > 200:
        t = 'gray'
    elif b > 180 and r < 120 and g < 180:
        t = 'blue'
    elif b > 200 and g > 170 and r > 100:
        t = 'lightblue'
    elif r > 180 and g < 100:
        t = 'red'
    elif r > 200 and g > 200 and b < 100:
        t = 'yellow'
    else:
        t = f'other({r},{g},{b})'
    if t != prev_type:
        if prev_type is not None:
            segments.append((start, x-1, prev_type))
        start = x
        prev_type = t
segments.append((start, 579, prev_type))

for s in segments:
    print(f'  x={s[0]}-{s[1]} ({s[1]-s[0]+1}px): {s[2]}')
"
